// Firebase Messaging Service Worker
// Generated by custom-push — do not edit manually.
// ─────────────────────────────────────────────────────────────────────────────

importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-app-compat.js')
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging-compat.js')

firebase.initializeApp({
  apiKey:            '{{API_KEY}}',
  authDomain:        '{{AUTH_DOMAIN}}',
  projectId:         '{{PROJECT_ID}}',
  storageBucket:     '{{STORAGE_BUCKET}}',
  messagingSenderId: '{{MESSAGING_SENDER_ID}}',
  appId:             '{{APP_ID}}'
})

const messaging = firebase.messaging()

/**
 * Extract an absolute URL from an FCM payload.
 */
function getAbsoluteUrl(payload, defaultPath = '/') {
  const path = payload.data?.action_url 
    || payload.data?.url 
    || payload.data?.route 
    || payload.data?.click_action 
    || payload.fcmOptions?.link 
    || defaultPath

  try {
    // If it's already an absolute URL, return it
    if (path.startsWith('http')) {
      return path
    }
    // Otherwise, resolve it relative to the service worker's origin
    const absoluteUrl = new URL(path, self.location.origin).href
    return absoluteUrl
  } catch (e) {
    console.error('[custom-push] Failed to parse URL:', path, e)
    return self.location.origin + '/'
  }
}

// Background message handler
messaging.onBackgroundMessage(function(payload) {
  console.log('[custom-push] Background message received:', payload)

  const title = payload.notification?.title || payload.data?.title || 'New Notification'
  const body = payload.notification?.body || payload.data?.body || ''
  const icon = payload.notification?.icon || payload.data?.icon || '/icon.png'
  const url = getAbsoluteUrl(payload)

  console.log('[custom-push] Preparing notification:', { title, body, icon, url })

  const options = {
    body: body,
    icon: icon,
    badge: '/badge.png',
    data: {
      ...payload.data,
      url: url // Store for click handler
    }
  }

  return self.registration.showNotification(title, options)
})

// Notification click handler
self.addEventListener('notificationclick', function(event) {
  console.log('[custom-push] Notification clicked:', event.notification.title)
  
  event.notification.close()

  const urlToOpen = event.notification.data?.url || self.location.origin + '/'
  console.log('[custom-push] Redirecting to:', urlToOpen)

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function(clientList) {
      // 1. Try to find an existing tab and navigate it
      for (const client of clientList) {
        if (client.url.includes(self.location.origin) && 'focus' in client) {
          console.log('[custom-push] Found existing tab, navigating...')
          try {
            client.navigate(urlToOpen)
            return client.focus()
          } catch (e) {
            console.error('[custom-push] Failed to navigate existing tab:', e)
          }
        }
      }

      // 2. If no tab found or navigation failed, open a new window
      if (clients.openWindow) {
        console.log('[custom-push] Opening new window...')
        return clients.openWindow(urlToOpen).catch(function(e) {
          console.error('[custom-push] openWindow failed:', e)
        })
      }
    }).catch(function(err) {
      console.error('[custom-push] Click handler failed:', err)
    })
  )
})
